"use client";

import { Fragment } from "react";
import { cn } from "@/lib/utils";

interface Keyboard1Props {
  keys?: string[];
  label?: string;
  className?: string;
}

export const keyboard1Demo: Keyboard1Props = {
  keys: ["⌘", "K"],
  label: "Quick search",
};

export function Keyboard1({
  keys = ["⌘", "K"],
  label,
  className,
}: Keyboard1Props) {
  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="inline-flex items-center gap-2.5 rounded-lg border border-border bg-card px-3 py-2 shadow-sm">
        {label && (
          <span className="text-xs font-medium text-muted-foreground">
            {label}
          </span>
        )}
        <div className="flex items-center gap-1">
          {keys.map((key, index) => (
            <Fragment key={index}>
              {index > 0 && (
                <span
                  className="text-xs text-muted-foreground/60"
                  aria-hidden="true"
                >
                  +
                </span>
              )}
              <kbd className="inline-flex h-5 min-w-5 items-center justify-center rounded-md border border-border border-b-2 bg-muted px-1.5 font-mono text-xs font-medium text-card-foreground">
                {key}
              </kbd>
            </Fragment>
          ))}
        </div>
      </div>
    </div>
  );
}

"use client";

import { Search } from "lucide-react";
import { Fragment } from "react";
import { cn } from "@/lib/utils";

interface Search1Props {
  placeholder?: string;
  shortcut?: string[];
  className?: string;
}

export const search1Demo: Search1Props = {
  placeholder: "Search anything...",
  shortcut: ["⌘", "K"],
};

export function Search1({
  placeholder = "Search...",
  shortcut,
  className,
}: Search1Props) {
  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-full max-w-72 items-center gap-2 rounded-lg border border-border bg-card px-3 py-2 shadow-sm">
        <Search
          className="size-3.5 shrink-0 text-muted-foreground"
          aria-hidden="true"
        />
        <span className="flex-1 truncate text-sm text-muted-foreground">
          {placeholder}
        </span>
        {shortcut && shortcut.length > 0 && (
          <div className="flex items-center gap-0.5" aria-hidden="true">
            {shortcut.map((key, i) => (
              <Fragment key={i}>
                {i > 0 && (
                  <span className="text-xs text-muted-foreground/60">+</span>
                )}
                <kbd className="inline-flex h-5 min-w-5 items-center justify-center rounded-md border border-border border-b-2 bg-muted px-1 font-mono text-xs font-medium text-muted-foreground">
                  {key}
                </kbd>
              </Fragment>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import {
  Cloud,
  CloudRain,
  CloudSnow,
  Moon,
  Sun,
} from "lucide-react";

import { cn } from "@/lib/utils";

type Condition = "sunny" | "cloudy" | "rainy" | "snowy" | "night";

interface Day {
  label: string;
  condition: Condition;
  high: number;
  low: number;
}

interface Weather2Props {
  days?: Day[];
  className?: string;
}

const iconMap: Record<Condition, typeof Sun> = {
  sunny: Sun,
  cloudy: Cloud,
  rainy: CloudRain,
  snowy: CloudSnow,
  night: Moon,
};

const iconColorMap: Record<Condition, string> = {
  sunny: "text-amber-500",
  cloudy: "text-slate-500",
  rainy: "text-sky-500",
  snowy: "text-cyan-500",
  night: "text-indigo-400",
};

export const weather2Demo: Weather2Props = {
  days: [
    { label: "Mon", condition: "sunny", high: 24, low: 15 },
    { label: "Tue", condition: "cloudy", high: 22, low: 14 },
    { label: "Wed", condition: "rainy", high: 18, low: 12 },
    { label: "Thu", condition: "cloudy", high: 19, low: 13 },
    { label: "Fri", condition: "sunny", high: 25, low: 16 },
  ],
};

export function Weather2({ days = [], className }: Weather2Props) {
  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-full max-w-64 items-center justify-between gap-1 rounded-xl border border-border bg-card px-3 py-3 shadow-sm">
        {days.map((day) => {
          const Icon = iconMap[day.condition];
          return (
            <div
              key={day.label}
              className="flex flex-col items-center gap-1"
            >
              <span className="text-xs font-medium text-muted-foreground">
                {day.label}
              </span>
              <Icon
                className={cn("size-5", iconColorMap[day.condition])}
                aria-hidden="true"
              />
              <div className="flex flex-col items-center">
                <span className="text-sm font-semibold tabular-nums text-card-foreground">
                  {day.high}°
                </span>
                <span className="text-xs tabular-nums text-muted-foreground">
                  {day.low}°
                </span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
